impl CapabilityDecision {
/// Checks bounded-list accounting and status-dependent wire invariants.
pub fn wire_invariants_valid(&self) -> bool {
let missing_len = u32::try_from(self.missing.len()).ok();
let contributors_len = u32::try_from(self.contributors.len()).ok();
let missing_accounted = match self.missing_completeness {
CollectionCompleteness::Complete => missing_len == Some(self.missing_total),
CollectionCompleteness::Truncated => missing_len.is_some_and(|len| len < self.missing_total),
};
let contributors_accounted = match self.contributors_completeness {
CollectionCompleteness::Complete => contributors_len == Some(self.contributors_total),
CollectionCompleteness::Truncated => contributors_len.is_some_and(|len| len < self.contributors_total),
};
let status_valid = match self.status {
SupportStatus::Supported => self.missing_total == 0
&& self.missing.is_empty()
&& self.location.is_none()
&& self.rejection_code.is_none(),
SupportStatus::Unsupported => self.rejection_code.is_none(),
SupportStatus::Rejected => self.rejection_code.is_some(),
};
missing_accounted && contributors_accounted && status_valid
}
}
